SELECT c.comment_id, c.user_id, c.product_id, c.product_type, c.score, c.content, 
       c.images, c.create_time, c.order_item_id, c.status, u.username
FROM comments c
LEFT JOIN users u ON c.user_id = u.user_id


        AND c.product_type = #{productType}


        AND c.status = #{status}


ORDER BY c.create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) 
FROM comments c


        AND c.product_type = #{productType}


        AND c.status = #{status}

SELECT comment_id, user_id, product_id, product_type, score, content, images, create_time, order_item_id, status
FROM comments
WHERE comment_id = #{commentId}
